// User manually fills linkedin_url after googling.
// This node generates the connection note for those rows.
const items = $input.all();
const filtered = items.filter(item => {
  const d = item.json;
  const status = (d.reply_status || '').trim().toLowerCase();
  const email  = (d.email        || '').trim();
  const name   = (d.contact_name || '').trim();
  const liUrl  = (d.linkedin_url || '').trim();
  const liNote = (d.linkedin_note || '').trim();

  // Sent emails that have a manually-added LinkedIn URL but no note yet
  return status === 'sent' && email !== '' && name !== '' && liUrl !== '' && liNote === '';
});
console.log(`[Filter] ${filtered.length} rows ready for note generation`);
if (filtered.length === 0) return [];
return filtered;

const response = $json;
const source = $('Build Connection Note Prompt').item.json;

let linkedinNote = '';

try {
  let content = response?.choices?.[0]?.message?.content || '';
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  const parsed = JSON.parse(content);
  linkedinNote = (parsed.linkedin_note || '').trim();

  if (linkedinNote.length > 280) linkedinNote = linkedinNote.substring(0, 280);

  // Formula injection guard
  if (['=','+','-','@'].includes(linkedinNote[0])) {
    linkedinNote = linkedinNote.substring(1);
  }

  console.log(`[Note] ${source.contact_name}: ${linkedinNote.length} chars`);
} catch (e) {
  console.log(`[Note] Parse failed: ${e.message}`);
  linkedinNote = '';
}

return {
  json: {
    email:         source.email,
    linkedin_url:  source.linkedin_url,
    linkedin_note: linkedinNote
  }
};
